<template>
    <div class="home">
        <div class="container flex">
            <div class="articleList">
                <div class="list-item flex" v-for="(item, index) in articleList" :key="index">
                    <div class="media">
                        <a :href="item.url" target="_bank" v-lazy:background-image="item.images[0]"></a>
                    </div>
                    <div class="content">
                        <div class="desc">
                            <a :href="item.url">{{item.desc}}</a>
                        </div>
                        <div class="footer flex">
                            <div>作者：{{item.author}}</div>
                            <div v-if="device!='mobile'">{{item.createdAt}}</div>
                            <div>浏览：{{item.views}}</div>
                        </div>
                    </div>
                </div>
            </div>
            <div class="randomGirl" v-if="device!='mobile'">
                <div class="media">
                    <a class="media-content" @click="getRandomGirl()" title="点我试试" target="_blank" v-lazy:background-image="randomGirl">
                        <span class="overlay"></span>
                    </a>
                    <div class="media-overlay">
                        <div class="flex">
                            <span class="day">{{ date.day }}</span>
                            <time class="year">{{ date.month }}月, {{ date.year }}</time>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import { mapState } from 'vuex';
export default {
    data(){
        return{
            articleList: [],
            randomGirl: '',
            date: {
                year: '',
                month: '',
                day: ''
            }
        }
    },
    computed: {
        ...mapState({
            device: state => state.app.device
        })
    },
    mounted() {
        this.getArticle();
        this.getRandomGirl();
        this.getNowTime();
    },
    methods: {
        getArticle(){
            this.axios.get(this.gankUrl+'/api/v2/hot/views/category/GanHuo/count/10').then((res) => {
                if(res.data.data){
                    this.articleList = res.data.data;
                }
            })
        },
        // 获取当前日期
        getNowTime(){
            var date = new Date();
            this.date.year = date.getFullYear();
            this.date.month = date.getMonth()+1;
            this.date.day = date.getDate();
        },
        // 随机图片，时间背景
        getRandomGirl(){
            this.axios.get(this.gankUrl+'/api/v2/random/category/Girl/type/Girl/count/1').then((res) => {
                if(res.data.data){
                    this.randomGirl = res.data.data[0].url;
                }
            })
        }
    }
}
</script>
<style lang="scss" scoped>
.home{
    position: relative;
    width: 100%;
    .container{
        position: relative;
        justify-content: space-between;
        width: 80%;
        margin: 0 auto;
    }
    .articleList{
        width: 60%;
        // @include bg_color($background-color-sub);
        .list-item{
            position: relative;
            flex-direction: row;
            word-wrap: break-word;
            padding: 15px 0;
            .media{
                position: relative;
                display: block;
                border-radius: 3px;
                flex-shrink: 0;
                align-items: flex-start;
                overflow: hidden;
                margin-right: 30px;
                width: 33.33%;
                a{
                    cursor: pointer;
                    @include font_color($font-color-light);
                    position: absolute;
                    top: 0;
                    bottom: 0;
                    left: 0;
                    right: 0;
                    border: 0;
                    border-radius: inherit;
                    background-size: cover;
                    background-repeat: no-repeat;
                    background-position: 50% 50%;
                    background-color: rgba(120, 120, 120, 0.1);
                }
                &::after{
                    content: '';
                    display: block;
                    padding-top: 66.66%;
                }
            }
            .content{
                display: flex;
                flex-direction: column;
                flex: 1 1 auto;
                justify-content: center;
                .desc{
                    flex: 1 1 auto;
                    a{
                        text-indent: 2em;
                        overflow: hidden;
                        display: -webkit-box;
                        -webkit-line-clamp: 2;
                        -webkit-box-orient: vertical;
                        @include font_color($font-color-light);
                        &:hover{
                            color: $yellow;
                        }
                    }
                }
                .footer{
                    margin-top: 15px;
                    justify-content: space-between;
                    div{
                        font-size: $font_medium_s;
                        margin-right: 10px;
                        @include font_color($font-color-light);
                        &:last-child{
                            margin-right: 0;
                        }
                    }
                }
            }
        }
    }
    .randomGirl{
        position: relative;
        border-radius: 3px;
        overflow: hidden;
        @include font_color($font-color-light);
        display: flex;
        flex-direction: column;
        word-wrap: break-word;
        width: 322px;
        .media{
            position: relative;
            display: block;
            overflow: hidden;
            border-radius: 3px;
            align-items: flex-start;
            flex-shrink: 0;
            .media-content{
                position: absolute;
                top: 0;
                bottom: 0;
                left: 0;
                right: 0;
                border: 0;
                cursor: pointer;
                border-radius: inherit;
                background-size: cover;
                background-repeat: no-repeat;
                background-position: 50% 50%;
                background-color: rgba(120, 120, 120, 0.1);
                color: #ffffff;
                .overlay{
                    width: 100%;
                    height: 100%;
                    background-color: rgba(0, 0, 0, 0.66);
                    position: absolute;
                    opacity: .22;
                    top: 0;
                    left: 0;
                    transition: opacity 0.3s ease-in-out;
                }
            }
            .media-overlay{
                position: absolute;
                top: 0;
                left: 0;
                right: 0;
                bottom: 0;
                padding: 0;
                z-index: 2;
                display: flex;
                bottom: auto;
                padding: 1.5rem;
                .flex{
                    font-family: nicetheme, Arial, sans-serif;
                    flex-direction: column;
                    .day{
                        color: #fff;
                        font-size: 3.5rem;
                        font-weight: 300;
                        line-height: 1;
                    }
                    .year{
                        font-size: 0.75rem;
                        color: #fff;
                        text-align: center;
                    }
                }
            }
            &::after{
                content: '';
                display: block;
                padding-top: 100%;
            }
        }
    }
}
@media screen and (max-width: 576px) {
    .home {
        .container {
            width: 90% !important;
        }
        .articleList{
            width: 100% !important;
            .media{
                margin-right: 20px !important;
            }
            .content{
                .desc{
                    a{
                        text-indent: 0 !important; 
                    }
                }
            }
        }
    }
}
</style>


